[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div></div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
.print-format { font-family: Arial, Helvetica, sans-serif; font-size: 10px; }
table { width: 100%; border-collapse: collapse; }
td { border: 1px solid #444; padding: 4px 5px; }
.label { width: 38%; font-weight: bold; background: #eee; }
.title { text-align: center; font-weight: bold; font-size: 14px; margin-bottom: 6px; }
