</style>
{% set latest_qi = frappe.db.sql("""
    SELECT name, custom_ar_number, status
    FROM `tabQuality Inspection`
    WHERE batch_no = %(batch)s AND docstatus = 1
        AND status = 'Accepted'
    ORDER BY report_date DESC, creation DESC
    LIMIT 1
""", {"batch": doc.name}, as_dict=True) if doc.name else [] %}
{% set party = doc.get("custom_party") or "" %}
